INSERT INTO `order` (
    user_id, lawyer_id, service_type_id, total_amount, status, created_time, updated_time, form_data
) VALUES (
    #{userId}, #{lawyerId}, #{serviceTypeId}, #{totalAmount}, #{status}, NOW(), NOW(), #{formData}
