mapper.update:
UPDATE `order`
user_id = #{userId}, lawyer_id = #{lawyerId}, service_type_id = #{serviceTypeId}, total_amount = #{totalAmount}, status = #{status}, form_data = #{formData}, updated_time = NOW()
WHERE order_id = #{orderId}

mapper.select:
SELECT o.order_id AS orderId, o.user_id AS userId, o.lawyer_id AS lawyerId, o.service_type_id AS serviceTypeId, o.total_amount AS totalAmount, o.status AS status, o.created_time AS createdTime, o.updated_time AS updatedTime, o.form_data AS formData, v.real_name AS lawyerName FROM `order` o LEFT JOIN lawyer l ON o.lawyer_id = l.lawyer_id LEFT JOIN users u ON l.user_id = u.user_id LEFT JOIN users_verfications v ON l.user_id = v.user_id
AND o.status = #{status}
AND o.service_type_id IN
#{item}
AND ( o.order_id LIKE CONCAT('%', #{keyword}, '%') OR v.real_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY o.created_time DESC LIMIT #{pageSize} OFFSET #{offset}
